// Kommo envia el body como form-urlencoded: claves planas tipo message[add][0][text].
// n8n lo deja en $json.body (objeto) o en $json directo. Soportamos ambos.
const body = ($json.body && typeof $json.body === 'object') ? $json.body : $json;
const get = (k) => body[k];

// entity_id de un webhook de mensaje/talk apunta al lead vinculado a la conversacion.
const entityId =
  get('talk[add][0][entity_id]') ||
  get('message[add][0][entity_id]') ||
  get('message[add][0][element_id]') ||
  '';

// contact_id por si Kommo lo incluye directo (atajo).
const contactIdDirecto =
  get('message[add][0][contact_id]') ||
  get('talk[add][0][contact_id]') ||
  '';

// Texto del mensaje entrante (donde viaja el codigo de referencia).
const text =
  get('message[add][0][text]') ||
  get('message[add][0][message]') ||
  get('message[add][0][comment]') ||
  '';

const m = String(text).match(/REF-[A-Za-z0-9]+/i);
const refCode = m ? m[0].toUpperCase() : '';

return [{ json: { entityId: String(entityId), contactIdDirecto: String(contactIdDirecto), refCode, text: String(text) } }];

// Determina el contact_id de quien escribio. Prioriza el contacto directo del webhook;
// si no, el contacto principal (is_main) del lead.
const parse = $('Parsear webhook entrante').item.json;
let contactId = parse.contactIdDirecto || '';

if (!contactId) {
  const lead = $json || {};
  const contactos = (lead._embedded && lead._embedded.contacts) || [];
  contactos.sort((a, b) => (b.is_main === true) - (a.is_main === true));
  contactId = contactos.length ? String(contactos[0].id) : '';
}

return [{ json: { contactId, refCode: parse.refCode } }];

// Extrae y normaliza el telefono del contacto. Match a la sheet por ref_code.
const contact = $json || {};
const refCode = $('Elegir contacto').item.json.refCode || '';
const contactId = $('Elegir contacto').item.json.contactId || '';

function normalizar(raw) {
  if (raw === null || raw === undefined) return '';
  let d = String(raw).replace(/[^\d]/g, '');
  if (d.length < 10) return '';
  if (!d.startsWith('58') && d.length === 10) d = '58' + d; // VE -> E.164 sin '+'
  return d;
}

let telefono = '';
const campos = contact.custom_fields_values || [];
for (const f of campos) {
  if (f.field_code === 'PHONE' || f.field_type === 'phone') {
    for (const v of (f.values || [])) {
      const t = normalizar(v.value);
      if (t) { telefono = t; break; }
    }
  }
  if (telefono) break;
}

// Si falta ref_code o telefono, no actualizamos: el barrido (2a instancia) lo recupera.
if (!refCode || !telefono) {
  console.log('Captura incompleta -> la tomara el barrido. refCode=' + refCode + ' telefono=' + telefono);
  return [];
}

return [{ json: { ref_code: refCode, telefono, kommo_contact_id: String(contactId), estado: 'chat_iniciado' } }];
